function candidate(input) {
  if (typeof input !== "string") {
    throw new TypeError("invalid-value");
  }

  const first = input.indexOf("'");
  const second = first === -1 ? -1 : input.indexOf("'", first + 1);

  if (first <= 0 || second === -1) {
    throw new TypeError("invalid-value");
  }

  const encoding = input.slice(0, first).toLowerCase();
  const payload = input.slice(second + 1);

  if (encoding !== "utf-8" && encoding !== "iso-8859-1") {
    throw new TypeError("unsupported-encoding");
  }

  const bytes = [];

  for (let i = 0; i < payload.length; i += 1) {
    const ch = payload.charCodeAt(i);

    if (payload[i] === "%") {
      const hex = payload.slice(i + 1, i + 3);
      if (!/^[0-9a-fA-F]{2}$/.test(hex)) {
        throw new TypeError("invalid-value");
      }
      bytes.push(parseInt(hex, 16));
      i += 2;
    } else {
      if (ch > 0x7f) {
        throw new TypeError("invalid-value");
      }
      bytes.push(ch);
    }
  }

  if (encoding === "iso-8859-1") {
    return String.fromCharCode.apply(null, bytes);
  }

  if (typeof TextDecoder === "function") {
    try {
      return new TextDecoder("utf-8", { fatal: true }).decode(new Uint8Array(bytes));
    } catch (error) {
      throw new TypeError("invalid-value");
    }
  }

  try {
    return decodeURIComponent(bytes.map(function (byte) {
      return "%" + byte.toString(16).padStart(2, "0");
    }).join(""));
  } catch (error) {
    throw new TypeError("invalid-value");
  }
}
